   *
   * 走 gateway plugin 一条路，没 IPC 兜底——pod 上 cowork plugin 是 source
   * of truth；Mac 端不应装 cowork.py。mini-tool 窗口的 client 通过
   * installDesktopAuthSideEffects 自动连 gateway，连不上时 client.cowork*
   * 直接抛错，错误信息进 mini-tool dialog 的 error 状态。
   */
  async function handleMiniToolLoadProject(projectId: string): Promise<MiniToolFlowProject | null> {
    const hasProjectId = Boolean(projectId)
    if (!projectId) {
      report(MetricsKey.MINI_TOOL_LOAD_PROJECT, { hasProjectId, outcome: 'missing' })
      return null
    }
    try {
      const list = await client.coworkListProjects<CoworkStudioListResult>({
        includeCoworkOnly: true,
      })
      const p = list.projects.find((x) => x.id === projectId)
      if (!p || p.guardCompliant !== true) {
        report(MetricsKey.MINI_TOOL_LOAD_PROJECT, { hasProjectId, outcome: 'missing' })
      } else if (p.cowork) {
        report(MetricsKey.MINI_TOOL_LOAD_PROJECT, { hasProjectId, outcome: 'published' })
      } else {
        report(MetricsKey.MINI_TOOL_LOAD_PROJECT, { hasProjectId, outcome: 'found' })
      }
      if (!p) return null
      return {
        id: p.id,
        name: p.name,
        title: p.title,
        srcDir: p.srcDir,
        guardCompliant: p.guardCompliant,
        cowork: p.cowork
          ? {
              workId: p.cowork.workId,
              accessUrl: p.cowork.accessUrl,
              coworkAppUrl: p.cowork.coworkAppUrl,
              version: p.cowork.version,
              alias: p.cowork.alias,
            }
          : undefined,
        dev: p.dev ? { url: p.dev.url, alive: p.dev.alive } : undefined,
      }
    } catch (err) {
      report(MetricsKey.MINI_TOOL_LOAD_PROJECT, {
        hasProjectId,
        outcome: 'error',
        errorMessage: err instanceof Error ? err.message : String(err),
      })
      throw err
    }
