/**
 * Fetch remote Cowork works via `cowork.py list --json`.
 *
 * The CLI prints raw Cowork API JSON (uppercase fields nested under data.list);
 * we shallow-normalize each entry into the cowork.* shape that Studio cards
 * expect, dropping anything we can't recognize.
 *
 * Empty result on any failure — Studio just won't show cowork-only rows.
 */

import type { CoworkStudioProject, CoworkVisibility } from "../types.js";
import { parseLastJsonLine, spawnCoworkCli } from "./cowork-cli.js";

const LIST_TIMEOUT_MS = 15_000;

/** Lossy field reader that survives unknown shapes. */
function readString(v: unknown): string | undefined {
  return typeof v === "string" ? v : undefined;
}
function readNumber(v: unknown): number | undefined {
  if (typeof v === "number" && Number.isFinite(v)) return v;
  if (typeof v === "string") {
    const n = Number(v);
    return Number.isFinite(n) ? n : undefined;
  }
  return undefined;
}
function readVisibility(v: unknown): CoworkVisibility | undefined {
  if (v === "SELF_ONLY" || v === "PARTIAL" || v === "ALL") return v;
  return undefined;
}

/**
 * Build a `cowork.*` block from one remote work record.
 *
 * Cowork API uses domain-prefixed fields on each work row
 * (deploymentAppId / deploymentAlias / deploymentAccessUrl / deploymentStatus
 * / visibilityScope). `cowork.py list` is enriched by default — each row gets
 * the detail-only fields backfilled — so we read the deployment* names first
 * and fall back to short variants for forward compat.
 */
function normalizeRemoteWork(raw: unknown): CoworkStudioProject | null {
  if (!raw || typeof raw !== "object") return null;
  const obj = raw as Record<string, unknown>;
  const workId = readNumber(obj.id ?? obj.workId ?? obj.work_id);
  const appId = readString(obj.deploymentAppId ?? obj.appId ?? obj.app_id);
  const accessUrl = readString(obj.deploymentAccessUrl ?? obj.accessUrl ?? obj.access_url);
  if (!workId || !appId || !accessUrl) return null;
  const alias = readString(obj.deploymentAlias ?? obj.alias);
  const name = readString(obj.name) ?? readString(obj.title) ?? alias ?? `Work #${workId}`;
  const title = readString(obj.title) ?? name;
  return {
    id: `cowork:${workId}`,
    name,
    title,
    createdAt: readNumber(obj.createdAt ?? obj.created_at),
    updatedAt: readNumber(obj.updatedAt ?? obj.updated_at),
    cowork: {
      workId,
      appId,
      alias,
      accessUrl,
      coworkAppUrl: readString(obj.coworkAppUrl ?? obj.cowork_app_url),
      deploymentId: readNumber(obj.deploymentId ?? obj.deployment_id) ?? 0,
      deploymentStatus: readString(obj.deploymentStatus ?? obj.deployment_status),
      visibility: readVisibility(obj.visibilityScope ?? obj.visibility),
      publishedAt: readNumber(obj.publishedAt ?? obj.published_at),
      version: readString(obj.version),
    },
    status: ["cowork-only"],
  };
}

interface CoworkListResponseShape {
  data?: { list?: unknown[]; works?: unknown[]; items?: unknown[] };
  list?: unknown[];
  works?: unknown[];
  items?: unknown[];
}

function extractList(payload: unknown): unknown[] {
  if (!payload) return [];
  // cowork.py list prints a top-level JSON array. Accept legacy {data:{list:[]}}
  // shapes too so we don't break if the upstream API ever changes.
  if (Array.isArray(payload)) return payload;
  if (typeof payload !== "object") return [];
  const obj = payload as CoworkListResponseShape;
  return (
    obj.data?.list ?? obj.data?.works ?? obj.data?.items ?? obj.list ?? obj.works ?? obj.items ?? []
  );
}

export async function fetchRemoteCoworkWorks(): Promise<CoworkStudioProject[]> {
  const result = await spawnCoworkCli(["list"], { timeoutMs: LIST_TIMEOUT_MS }).catch(() => null);
  if (!result || result.code !== 0) return [];
  const payload = parseLastJsonLine<unknown>(result.stdout);
  if (!payload) {
    // cowork.py list 当前打印的不是单行 JSON 而是 indented；尝试整体 parse
    try {
      const all = JSON.parse(result.stdout) as unknown;
      return extractList(all)
        .map(normalizeRemoteWork)
        .filter((p): p is CoworkStudioProject => p !== null);
    } catch {
      return [];
    }
  }
  return extractList(payload)
    .map(normalizeRemoteWork)
    .filter((p): p is CoworkStudioProject => p !== null);
}
