export async function listCoworkProjects(
  options: ListProjectsOptions = {},
): Promise<CoworkStudioProject[]> {
  // 两个扫描根：
  //   1. ~/.openclaw/workspace/cowork/   <- 约定位置，所有新项目都在这里
  //   2. ~/.openclaw/workspace/code/     <- legacy 兼容，老项目迁走后可以去掉
